def match_pattern(query, threshold=0.75):
    ql = query.lower(); best = None; best_s = 0.0
    for name, p in PATTERNS.items():
        for t in p["triggers"]:
            score = 1.0 if t in ql else (len(set(ql.split()) & set(t.split())) / max(len(set(t.split())), 1)) * 0.8
            if score > best_s: best_s = score; best = name
    return (best, best_s) if best and best_s >= threshold else None
def generate_from_pattern(name, ctx): return PATTERNS[name]["gen"](ctx)
def list_patterns(): return [{"name": n, "triggers": p["triggers"]} for n, p in PATTERNS.items()]
